<section class="card form-card"><h2>Upload land document</h2><form class="grid-form" method="post" action="/documents/upload" enctype="multipart/form-data"><?= csrf_field() ?><label>Document type <input name="doc_type" required></label><label>Plot UUID <input name="plot_id"></label><label>Owner UUID <input name="owner_id"></label><label>Transaction UUID <input name="transaction_id"></label><label class="upload-zone span-2">File <input type="file" name="document" accept=".pdf,.jpg,.jpeg,.png,.docx" required></label><button class="btn primary">Upload</button></form></section>
